body:
Calling wait(0) in a task causes an upper calling task to keep going and not wait.

This was found by reducing the failing UVM tests/20sequences/90Mantis/8513_kill_sequence_activity and tests/20sequences/90Mantis/3129_seq_kill  (and likely others).

@ArturBieniek4 might you be able to take a look?  Thanks!

<details>
<summary>Example</summary>

```
// verilog_format: off
`define DBGF(msg)  do begin $write("- DBG[%0t] %s:%05d: %m: ", $time, `__FILE__, `__LINE__); $display msg; end while(0)
`define stop $stop
`define checkh(gotv,expv) do if ((gotv) !== (expv)) begin $write("%%Error: %s:%0d:  got=%0x exp=%0x (%s !== %s)\n", `__FILE__,`__LINE__, (gotv), (expv), `"gotv`", `"expv`"); `stop; end while(0);
// verilog_format: on


class uvm_sequence;
  bit m_called;
  bit m_returned;

  virtual task body();
  endtask

  virtual task start();
    fork
      begin
        #0;
        m_called = 1;
        `DBGF(("call body()"));
        body();
        `DBGF(("called body() SHOULD NOT GET HERE"));
        m_returned = 1;
        #0;
      end
    join
  endtask
endclass

class blocking_sequence extends uvm_sequence;
  task body();
    `DBGF(("body() about to wait(0)"));
    wait (0);
    `DBGF(("body() did wait(0) - properly don't get here"));
  endtask
endclass

module t;
  bit timeout;
  initial begin
    blocking_sequence b;
    b = new;
    fork
      begin
        b.start();
      end
      begin
        #10;
        `DBGF(("main timeout (as expected)"));
        timeout = 1;
      end
    join_any
    `checkh(b.m_called, 1);
    `checkh(b.m_returned, 0);
    `checkh(timeout, 1);
    $finish;
  end

endmodule
```
</details>

